interface Product {
  id: number;
  name: string;
  price: number;
  description?: string;
  readonly createdAt: Date;
}

function displayProduct(product: Product): string {
  return `${product.name}: $${product.price}`;
}

const item: Product = {
  id: 1,
  name: "Laptop",
  price: 999.99,
  createdAt: new Date()
};

interface StringMap {
  [key: string]: string | number;
}

const env: StringMap = {
  NODE_ENV: "development",
  PORT: 3000
};
